// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_R 1000000
#define MAX_C 1000000
#define MAX_W 200000

int R, C, W;
int walls[MAX_W][4];
int graph[MAX_R][MAX_C];

void dfs(int r, int c, int visited[MAX_R][MAX_C]) {
    if (r < 0 || r >= R || c < 0 || c >= C || visited[r][c]) return;
    visited[r][c] = 1;
    if (r > 0 && graph[r-1][c] == 0) dfs(r-1, c, visited);
    if (r < R-1 && graph[r+1][c] == 0) dfs(r+1, c, visited);
    if (c > 0 && graph[r][c-1] == 0) dfs(r, c-1, visited);
    if (c < C-1 && graph[r][c+1] == 0) dfs(r, c+1, visited);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &R, &C, &W);
        for (int i = 0; i < W; i++) {
            scanf("%d %d %d %d", &walls[i][0], &walls[i][1], &walls[i][2], &walls[i][3]);
            walls[i][0]--; walls[i][1]--; walls[i][2]--; walls[i][3]--;
        }
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < W; i++) {
            if (walls[i][0] == walls[i][2]) {
                graph[walls[i][0]][Math.min(walls[i][1], walls[i][3])] = 1;
            } else {
                graph[Math.min(walls[i][0], walls[i][2])][walls[i][1]] = 1;
            }
        }
        int visited[MAX_R][MAX_C];
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                visited[i][j] = 0;
            }
        }
        dfs(0, 0, visited);
        int count = 0;
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                if (!visited[i][j]) count++;
            }
        }
        if (count == 0) printf("Chefland is doomed\n");
        else printf("%d\n", count);
    }
    return 0;
}

